# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

from flask import Flask, redirect, request, session, url_for, jsonify
import requests
import secrets
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

AUTHORIZATION_BASE_URL = os.environ.get('AUTHORIZATION_BASE_URL', 'https://authorization-server.com/oauth/authorize')
TOKEN_URL = os.environ.get('TOKEN_URL', 'https://authorization-server.com/oauth/token')
CLIENT_ID = os.environ.get('CLIENT_ID', 'your_client_id')
CLIENT_SECRET = os.environ.get('CLIENT_SECRET', 'your_client_secret')
REDIRECT_URI = os.environ.get('REDIRECT_URI', 'http://localhost:5000/callback')
SCOPE = os.environ.get('SCOPE', 'read write')

@app.route('/')
def index():
    if 'access_token' in session:
        return jsonify({
            'message': 'Logged in successfully',
            'access_token': session['access_token']
        })
    return jsonify({
        'message': 'Not logged in',
        'login_url': url_for('login', _external=True)
    })

@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    
    params = {
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'response_type': 'code',
        'scope': SCOPE,
        'state': state
    }
    
    authorization_url = f"{AUTHORIZATION_BASE_URL}?client_id={params['client_id']}&redirect_uri={params['redirect_uri']}&response_type={params['response_type']}&scope={params['scope']}&state={params['state']}"
    
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'Authorization code not provided'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Accept': 'application/json'
    }
    
    response = requests.post(TOKEN_URL, data=token_data, headers=headers)
    
    if response.status_code != 200:
        return jsonify({
            'error': 'Failed to obtain access token',
            'details': response.text
        }), 400
    
    token_response = response.json()
    access_token = token_response.get('access_token')
    
    if not access_token:
        return jsonify({'error': 'Access token not found in response'}), 400
    
    session['access_token'] = access_token
    
    if 'refresh_token' in token_response:
        session['refresh_token'] = token_response['refresh_token']
    
    if 'expires_in' in token_response:
        session['expires_in'] = token_response['expires_in']
    
    session.pop('oauth_state', None)
    
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})

@app.route('/protected')
def protected():
    access_token = session.get('access_token')
    
    if not access_token:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify({
        'message': 'This is a protected resource',
        'access_token': access_token
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)